$(window).on("load", () => {
    var imgLogo=this.drawLogo();
    $('#preloader-logo').html(imgLogo);
    $('#preload-text').html('Cargado');
});

$(document).ready(()=>{
    $('#preloader').fadeOut(800, () => {
        $('body').css('overflow', "visible");
        $('body').css("margin-top", "10px");

    });
});

